visualizer.shader:
  setMaxIterations(14);
  setStepSize(0.3282379869785127);

  let size = input();
  let pointerDown = input();
  time *= 0.9283287663605639; // Randomize time multiplier between 0.1 and 1
  rotateY(mouse.x * -5 * PI / 2 + time - (pointerDown + 0.1));
  rotateX(mouse.y * 5 * PI / 2 + time);

  // Set color
  color(getRayDirection().z, getRayDirection().y, 0.6439706727352774);

  // Get the current coordinate space once and store in s
  let s = getSpace();

  // Add rotations
  rotateX(getRayDirection().y * 1.6433527398721441 + time);
  rotateY(getRayDirection().x * 1.213901432831976 + time);
  rotateZ(getRayDirection().z * 2.7042123257269144 + time);

  // Apply metal and shine
  metal(0.39433751950552626 * size);
  shine(0.7653105149809418);

  // Render the shapes
  grid(4, size * 0.9804420049544316 - pointerDown * 0.05 / 3, 0.01 * size * 0.9804420049544316 - pointerDown * 0.05);
expand(noise(s * 1.2319501726815334) * 0.0540782757156445); boxFrame(vec3(size * 0.6327209467255018 - pointerDown * 0.05), size * 0.6327209467255018 - pointerDown * 0.05 * 0.1);
expand(noise(s * 0.558070945791699) * 0.4443645288565007); sphere(size * 0.5655253804119734 - pointerDown * 0.05 / 2);

  // Apply blending
  blend(nsin(time * size) * 0.1600182210374048);

  // Extra shape
  boxFrame(vec3(size * 0.7), size * 0.05);
